const mobilityData = items[0].json; // Assuming JSON array of routes

// Simple sustainability score calculation example
const optimizedRoutes = mobilityData.routes.map(route => {
  // Example: Incorporate bike lanes, public transport options, and traffic congestion
  const sustainabilityScore = (route.bikeLanePercentage * 0.4) + (route.publicTransportAvailability * 0.4) - (route.trafficCongestion * 0.2);

  return {
    ...route,
    sustainabilityScore
  };
});

// Sort routes descending by sustainabilityScore
optimizedRoutes.sort((a, b) => b.sustainabilityScore - a.sustainabilityScore);

return [{ json: { optimizedRoutes } }];

const routes = items[0].json.optimizedRoutes;

// Carbon footprint calculation assumptions (kg CO2 per km)
const carbonFactors = {
  car: 0.192,
  publicTransport: 0.105,
  bike: 0,
  walk: 0
};

const routesWithCarbon = routes.map(route => {
  // weighted average based on travel mode
  const distance = route.distanceKm;
  const mode = route.travelMode; // Assume travelMode: 'car', 'publicTransport', 'bike', 'walk'
  const carbonFootprint = carbonFactors[mode] ? carbonFactors[mode] * distance : 0;

  return {
    ...route,
    carbonFootprint
  };
});

return [{ json: { routesWithCarbon } }];

const routes = items[0].json.routesWithCarbon;

const bestRoute = routes[0];

const suggestions = [];

// Suggest alternatives if carbon footprint is high
if (bestRoute.carbonFootprint > 1) {
  if (bestRoute.travelMode === 'car') {
    suggestions.push('Consider switching to public transportation or carpooling to reduce your carbon footprint.');
  }
  if (bestRoute.travelMode === 'publicTransport' && bestRoute.sustainabilityScore < 0.5) {
    suggestions.push('Try adjusting your departure time to reduce waiting and emissions.');
  }
  if (bestRoute.travelMode === 'bike' || bestRoute.travelMode === 'walk') {
    suggestions.push('Great choice! Keep it up for a sustainable commute.');
  }
} else {
  suggestions.push('Your selected route is optimized for sustainability. Keep it up!');
}

return [{ json: { bestRoute, suggestions } }];

const analytics = items[0].json;

const chartData = analytics.map(row => ({
  date: row.date,
  avgCarbonFootprint: parseFloat(row.avgCarbonFootprint),
  travelMode: row.travelMode
}));

return [{ json: { chartData } }];
